import javax.jws.WebMethod;
import javax.jws.WebParam;
import javax.jws.WebService;
import javax.xml.ws.Endpoint;
import java.util.Iterator;
import javax.xml.parsers.DocumentBuilder;
import javax.xml.parsers.DocumentBuilderFactory;
import org.w3c.dom.Document;
import org.w3c.dom.Element;
import org.w3c.dom.NodeList;

@WebService
public class OrderProcessingService {

    @WebMethod
    public String processOrder(@WebParam(name = "orderRequest") String orderXml) {
        try {
            DocumentBuilderFactory factory = DocumentBuilderFactory.newInstance();
            DocumentBuilder builder = factory.newDocumentBuilder();
            Document document = builder.parse(new java.io.ByteArrayInputStream(orderXml.getBytes()));

            NodeList itemList = document.getElementsByTagName("item");
            double totalPrice = 0.0;

            for (int i = 0; i < itemList.getLength(); i++) {
                Element itemElement = (Element) itemList.item(i);
                double price = Double.parseDouble(itemElement.getElementsByTagName("price").item(0).getTextContent());
                int quantity = Integer.parseInt(itemElement.getElementsByTagName("quantity").item(0).getTextContent());
                totalPrice += price * quantity;
            }

            // Add additional order processing logic here if needed

            return "Order processed successfully. Total Price: $" + totalPrice;
        } catch (Exception e) {
            e.printStackTrace();
            return "Error processing order.";
        }
    }

    public static void main(String[] args) {
        Endpoint.publish("http://localhost:8080/OrderProcessingService", new OrderProcessingService());
        System.out.println("Service started at http://localhost:8080/OrderProcessingService");
    }
}